module RefModule(clk, reset, in, out);input clk;
    input reset;    
    input in;
    output out;
    reg out;


    parameter A=0, B=1;

    reg present_state, ctrl_bus_wire;

    always @(posedge clk) begin
        if (reset) begin  

            present_state <= B;
            out = 1;
        end else begin
            case (present_state)

                A: ctrl_bus_wire = (in)? A : B;
                B: ctrl_bus_wire = (in)? B : A;
            endcase


            present_state = ctrl_bus_wire;   

            case (present_state)

                A: out = 0;
                B: out = 1;
            endcase
        end
    end

endmodule
